 /**
- * Allocate an integer-cent total across positive integer weights.
- * Stub — the coding agent implements this at eval time (task 002).
+ * Allocate an integer-cent total proportionally across a set of positive
+ * weights. The sum of the returned shares is guaranteed to equal the total.
  */
 export function allocateProportional(total: number, weights: number[]): number[] {
-  throw new Error(`allocateProportional not implemented (total ${total}, ${weights.length} weights)`);
+  if (weights.length === 0) {
+    throw new Error("Cannot allocate to empty weights");
+  }
+  if (weights.some(w => w <= 0)) {
+    throw new Error("Weights must be positive numbers");
+  }
+
+  const sumOfWeights = weights.reduce((sum, w) => sum + w, 0);
+  let allocatedSum = 0;
+  const allocations: number[] = [];
+
+  for (let i = 0; i < weights.length - 1; i++) {
+    const share = roundToCents((total * weights[i]) / sumOfWeights);
+    allocations.push(share);
+    allocatedSum += share;
+  }
+
+  allocations.push(total - allocatedSum);
+
+  return allocations;
 }
